                    val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)
                    val urls = extractUrls(sharedText)
                    processSharedText(sharedText, sharedSubject, urls)
                }

                if (imageUri != null) {
                    processSharedImages(listOf(imageUri))
                }
            }
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        val type = intent.type.orEmpty()
        if (type.startsWith("image/")) {
            val imageUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java).orEmpty()
            if (imageUris.isNotEmpty()) {
                processSharedImages(imageUris)
            }
        }
    }

    private fun extractUrls(text: String?): List<String> {
        if (text.isNullOrBlank()) return emptyList()
        val matcher = Patterns.WEB_URL.matcher(text)
        val results = mutableListOf<String>()
        while (matcher.find()) {
            results.add(matcher.group())
        }
        return results.distinct()
    }

